INSERT INTO products (id, category_id, name, description, price, stock_quantity, rating, num_reviews, specifications) VALUES
(439, 17, 'Tamron 18-300mm F/3.5-6.3 Di III-A VC VXD Lens (Sony APS-C)', 'Versatile 18-300mm all-in-one zoom lens for Sony APS-C mirrorless cameras. VC image stabilisation and VXD autofocus motor.', 79990.00, 15, 4.7, 340, '{"Brand": "Tamron", "Focal Length": "18-300mm", "Aperture": "F/3.5-6.3", "Mount": "Sony E", "Stabilisation": "VC", "Color": "Black"}'),
(440, 17, 'Crossbeats Lumex Solis 4K Smart Projector (Google TV, 1000 ANSI, 300" Screen)', 'Native 1080p, Android 14, WiFi, Google TV certified projector. 1000 ANSI lumens, built-in streaming apps. Supports 300" display.', 34999.00, 30, 4.5, 980, '{"Brand": "Crossbeats", "Resolution": "4K/1080p Native", "Lumens": "1000 ANSI", "OS": "Android 14 Google TV", "Screen": "300 inch", "WiFi": "Yes"}'),
(441, 17, 'Redmi Pad 2 11" Wi-Fi + Cellular 6GB/128GB (2.5K, 9000mAh, HyperOS 2)', 'Redmi Pad 2 with a sharp 2.5K display, 9000mAh battery, Dolby Atmos, Active Pen support and HyperOS 2. Graphite Grey.', 22999.00, 40, 4.6, 2100, '{"Brand": "Redmi", "RAM": "6GB", "Storage": "128GB", "Display": "11-inch 2.5K", "Battery": "9000mAh", "OS": "HyperOS 2", "Color": "Graphite Grey"}'),
(442, 17, 'OnePlus Nord Buds 3r TWS Earbuds (54Hr Playback, 12.4mm, 47ms Low Latency)', 'Up to 54-hour playback, 2-mic clear calls, 3D Spatial Audio, AI Translation, dual-device connectivity. Ash Black.', 1799.00, 120, 4.4, 4500, '{"Brand": "OnePlus", "Driver": "12.4mm", "Battery": "54 Hours total", "Latency": "47ms", "Color": "Ash Black", "Feature": "3D Spatial Audio, AI Translation"}'),
(443, 17, 'Portronics Beem 440 Smart LED Projector (720p, 2000 Lumens, Netflix/Prime)', 'Smart LED projector with 720p HD, 2000 lumens brightness, built-in Netflix/Prime Video/Hotstar, rotatable design and screen mirroring.', 12999.00, 35, 4.3, 1800, '{"Brand": "Portronics", "Resolution": "720p HD", "Lumens": "2000", "App Support": "Netflix, Prime, Hotstar", "Speaker": "3W", "Color": "White"}'),
(444, 17, 'Sony WH-CH520 Wireless Bluetooth Headphones (50Hr Battery, DSEE, Multipoint)', 'On-ear wireless headphones with 50-hour battery, quick charge, DSEE audio upscaling, multipoint connectivity and voice assistant.', 4990.00, 80, 4.5, 8900, '{"Brand": "Sony", "Battery": "50 Hours", "Feature": "DSEE Upscale, Quick Charge", "Connectivity": "Multipoint BT", "Color": "Black", "Type": "On-Ear"}'),
(445, 17, 'E GATE Atom 3X 4K Projector (1080p Native, AutoFocus, WiFi6, Android)', 'Automatic home projector with 4K support, full HD 1080p native, auto 4D keystone, rotatable design, Android with Netflix/Prime, and ARC-HDMI.', 24999.00, 25, 4.4, 1200, '{"Brand": "E GATE", "Resolution": "4K/1080p Native", "Lumens": "300 ISO", "WiFi": "WiFi-6", "Feature": "AutoFocus, Auto Keystone"}'),
(446, 17, 'Portronics Tornado Mini Rechargeable Air Duster (130000 RPM, Type-C)', 'Compact cordless air duster for cleaning computers, cars and home. Up to 130000 RPM, adjustable speed, rechargeable via Type-C.', 1999.00, 100, 4.3, 2600, '{"Brand": "Portronics", "Max Speed": "130000 RPM", "Charging": "Type-C", "Type": "Air Duster", "Color": "Black", "Power": "Cordless"}'),
(447, 22, 'Caresmith Bloom Electronic Callus Remover (3 Crystal Quartz Heads)', 'Electronic foot scrubber with 3 crystal quartz heads. Removes dead skin, calloused feet and rough patches. Ideal pedicure kit.', 1299.00, 90, 4.4, 3100, '{"Brand": "Caresmith", "Heads": "3 Crystal Quartz", "Type": "Electronic Callus Remover", "For": "Women/Men", "Use": "Foot Dead Skin Removal"}'),
(448, 17, 'Portronics Snapcase 2 60W Fast Charging Cable Kit (USB-A & Type-C)', 'Multifunctional fast charging data cable kit with retractable cable and conversion heads for Micro/Lightning. Includes SIM storage and eject pin.', 999.00, 150, 4.3, 1900, '{"Brand": "Portronics", "Wattage": "60W", "Cable Types": "Micro, Lightning", "Feature": "Retractable, SIM Storage", "Connector": "USB-A & Type-C"}'),
(449, 17, 'WZATCO Yuva Go Pro Smart Projector (Auto Focus, 12000 Lumens, Android 13, WiFi 6)', 'Fully automatic 1080p native projector with auto focus, auto 4D keystone, 12000 lumens and 4K HDR support. WiFi 6, Bluetooth, ARC.', 29999.00, 20, 4.5, 780, '{"Brand": "WZATCO", "Resolution": "1080p Native", "Lumens": "12000", "OS": "Android 13", "WiFi": "WiFi 6", "Feature": "AutoFocus, Auto Keystone"}'),
(450, 17, 'APC Back-UPS BX600C-IN 600VA/360W UPS System', 'Reliable UPS for home office and desktop. Protects against power cuts, surges and voltage fluctuations. 600VA / 360W output.', 4999.00, 60, 4.5, 3400, '{"Brand": "APC", "Capacity": "600VA / 360W", "Voltage": "230V", "Type": "UPS System", "Use": "Home Office, Desktop PC"}'),
(451, 17, 'pTron Fusion Tunes 10W Bluetooth Speaker with Karaoke Mic & RGB Lights', 'Mini Bluetooth speaker with wireless karaoke mic, 8-hour playtime, vivid RGB lights, voice effects and BT5.1. Type-C charging.', 1499.00, 100, 4.2, 2200, '{"Brand": "pTron", "Wattage": "10W", "Battery": "8 Hours", "Feature": "Karaoke Mic, RGB, BT 5.1", "Charging": "Type-C", "Color": "Black"}'),
(452, 17, 'Portronics Ruffpad 8.5" LCD Writing Pad for Drawing & Handwriting', 'Re-writable LCD e-writing pad for drawing, note-taking and play. No paper needed – great gift for kids & adults.', 799.00, 180, 4.3, 4700, '{"Brand": "Portronics", "Screen": "8.5 inch LCD", "Type": "LCD Writing Pad", "For": "Kids & Adults", "Color": "Black"}'),
(453, 17, 'RTS USB Universal Travel Adapter (All-in-One, 100-250V, USB 2.1A)', 'International travel power adapter with multi-type outlets and 2.1A USB charging. Works with 100-250V. Compact and compact.', 849.00, 200, 4.1, 3800, '{"Brand": "RTS", "Voltage": "100-250V", "USB Output": "2.1A", "Type": "Universal Travel Adapter", "Color": "Black"}'),
(454, 17, 'Portronics Snapcase 3 60W Multi Cable Kit (USB-A + Type-C, Pocket Size)', 'Pocket-sized multifunctional charging kit with USB-A & Type-C heads, data transfer, SIM storage and eject pin. Blue edition.', 1099.00, 130, 4.3, 1600, '{"Brand": "Portronics", "Wattage": "60W", "Cable Types": "Micro, Type-C, Lightning", "Feature": "SIM Storage, Data Transfer", "Color": "Blue"}'),
(455, 17, 'Lifelong Electronics 20000mAh 22.5W Power Bank (3 Inputs, 6 Outputs)', 'High-capacity power bank with 22.5W fast charging, 3 inputs and 6 output ports including built-in cables for USB-A, Type-C and Lightning.', 2499.00, 90, 4.4, 3100, '{"Brand": "Lifelong", "Capacity": "20000mAh", "Charging": "22.5W Fast", "Inputs": "3", "Outputs": "6 (incl. built-in cables)", "Size": "Pocket Size"}'),
(456, 17, 'SaleOn 8.3x5" Tech Pouch Cable Organizer (1 Year Warranty)', 'Portable storage organizer for USB cables, chargers, earphones, power banks and digital gadgets. Travel mobile bag for men.', 699.00, 200, 4.4, 2900, '{"Brand": "SaleOn", "Size": "8.3x5 inch", "Type": "Tech Pouch Organizer", "Warranty": "1 Year", "For": "Travel/Daily Use"}'),
(457, 17, 'GLUN Digital LED Luggage Weighing Scale (50kg/110Lb)', 'Portable digital weighing scale with backlit LED screen. Accurate up to 50kg. Ideal for travel luggage weighing.', 399.00, 300, 4.2, 5200, '{"Brand": "GLUN", "Capacity": "50 Kg / 110 Lb", "Display": "LED", "Type": "Luggage Scale", "Power": "Battery"}'),
(458, 17, 'Btag SF-400 Digital Kitchen Scale (10Kg x 1g, LCD Display)', 'Precision kitchen weighing scale with 10kg capacity and 1g accuracy. LCD display, compact design for cooking and baking.', 499.00, 250, 4.3, 6800, '{"Brand": "Btag", "Capacity": "10 Kg", "Accuracy": "1g", "Display": "LCD", "Type": "Kitchen Scale", "Color": "White"}'),
(459, 17, 'APC Back-UPS BX1100C-IN 1100VA/660W UPS System', 'Heavy-duty UPS for home office providing 1100VA / 660W of power protection against outages and surges.', 8499.00, 40, 4.6, 2100, '{"Brand": "APC", "Capacity": "1100VA / 660W", "Voltage": "230V", "Type": "UPS System", "Use": "Home Office, Desktop PC"}'),
(460, 17, 'SoftLogic Movable Trolley Floor Stand for TV/Panel 42"-100"', 'Height-adjustable movable trolley stand for TVs and interactive flat panels. Supports 42" to 100" screens. For educational and corporate use.', 12999.00, 20, 4.4, 480, '{"Brand": "SoftLogic", "Compatible Size": "42-100 inch", "Type": "Floor Stand/Trolley", "Adjustable": "Height", "Use": "Education, Corporate"}');
